/**
 * Tile generation for polygon-based analysis orchestration.
 *
 * Generates a 2-D grid of tiles covering a GeoJSON polygon bounding box
 * with 50% overlap. Tile IDs are deterministic UUID5 values derived from
 * the polygon geometry and grid position.
 *
 * Coordinate convention: x=longitude, y=latitude, matching GeoJSON [lon, lat].
 *
 * Projection: local tangent plane approximation for meter-to-degree conversion.
 * Accurate for city-scale polygons (< ~50 km span).
 */

import { v5 as uuidv5 } from 'uuid'
import { PolygonValidationError } from '../errors'
import { arrayMax, arrayMin } from '../utils'
import { getTilingConfig, type TilingConfig, WIND_TILING_CONFIG } from './config'
import type { GeoJSONPolygon, Point, Tile, TileGrid, TileSize } from './types'
import { MAX_NON_EMPTY_TILES, METERS_PER_DEG_LAT, TILE_SIZE_M } from './types'
import { validatePolygon } from './validation'

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/** UUID5 namespace for deterministic tile IDs: uuid5(NAMESPACE_DNS, "tiles.infrared.city"). */
const DNS_NAMESPACE = '6ba7b810-9dad-11d1-80b4-00c04fd430c8'
export const TILE_NAMESPACE = uuidv5('tiles.infrared.city', DNS_NAMESPACE)

// ---------------------------------------------------------------------------
// TileService
// ---------------------------------------------------------------------------

export interface TileServiceOptions {
  /** A GeoJSON Polygon object. Validated and winding-order-normalized on construction. */
  polygon: unknown
  /** Optional maximum number of non-empty tiles (default: 100). */
  maxTilesOverride?: number
  /**
   * Analysis type — determines which tiling config (wind vs solar/etc.) drives
   * tile spacing. Wind: 256m step (50% overlap). Solar/UTCI/etc.: 512m step
   * (edge-to-edge). Defaults to wind config for backwards compatibility.
   */
  analysisType?: string
}

/**
 * Generate a grid of tiles covering a GeoJSON polygon.
 *
 * Validates the polygon, generates the tile grid with the appropriate spacing
 * for the analysis type (wind: 50% overlap; solar/etc.: edge-to-edge), marks
 * empty tiles, and enforces the non-empty tile limit.
 */
export class TileService {
  readonly polygon: GeoJSONPolygon
  readonly points: readonly Point[]
  readonly tileSize: TileSize
  readonly maxNonEmpty: number
  readonly tilingConfig: TilingConfig

  constructor(options: TileServiceOptions) {
    this.polygon = validatePolygon(options.polygon)
    this.tileSize = { x: TILE_SIZE_M, y: TILE_SIZE_M }
    this.maxNonEmpty = options.maxTilesOverride ?? MAX_NON_EMPTY_TILES
    this.tilingConfig = options.analysisType
      ? getTilingConfig(options.analysisType)
      : WIND_TILING_CONFIG

    // Convert GeoJSON ring to internal Point list (exclude closing vertex)
    const ring = this.polygon.coordinates[0]
    this.points = ring.slice(0, -1).map((pos) => ({
      latitude: pos[1],
      longitude: pos[0],
    }))
  }

  /**
   * Generate a grid of tiles covering the polygon's bounding box.
   *
   * Returns a TileGrid where tiles[row][col] is a Tile.
   * Row 0 is the southernmost row; column 0 is the westernmost column.
   * Each tile is marked empty=true if it does not intersect the polygon.
   *
   * @throws PolygonValidationError if the number of non-empty tiles exceeds maxNonEmpty.
   */
  generateTilesForPolygon(): TileGrid {
    if (this.points.length === 0) {
      throw new PolygonValidationError('Polygon has no vertices.')
    }

    const tiles = generateTiles(this.points, this.tileSize, this.tilingConfig.stepM)

    // Enforce non-empty tile limit
    let nonEmpty = 0
    for (const row of tiles) {
      for (const tile of row) {
        if (!tile.empty) nonEmpty++
      }
    }

    if (nonEmpty > this.maxNonEmpty) {
      throw new PolygonValidationError(
        `Polygon produces ${nonEmpty} non-empty tiles, exceeding the limit of ${this.maxNonEmpty}. Use maxTilesOverride to increase the limit.`,
      )
    }

    return {
      tiles,
      numRows: tiles.length,
      numCols: tiles.length > 0 ? tiles[0].length : 0,
      polygon: this.polygon,
      // Python parity (commits 00f5f97 / eef3917 on staging): the active
      // tiling config travels with the grid so downstream layer-assignment
      // (vegetation, ground-materials) uses the right stride for solar
      // analyses instead of silently falling back to the wind preset.
      config: this.tilingConfig,
    }
  }
}

// ---------------------------------------------------------------------------
// Geometry helpers
// ---------------------------------------------------------------------------

/** Ray casting algorithm for point-in-polygon. Uses lat as Y, lng as X. */
function pointInPolygon(lat: number, lng: number, polygon: readonly Point[]): boolean {
  const n = polygon.length
  if (n < 3) return false

  let inside = false
  let j = n - 1
  for (let i = 0; i < n; i++) {
    const yi = polygon[i].latitude
    const xi = polygon[i].longitude
    const yj = polygon[j].latitude
    const xj = polygon[j].longitude

    const intersect =
      yi > lat !== yj > lat && lng < ((xj - xi) * (lat - yi)) / (yj - yi + 1e-12) + xi
    if (intersect) {
      inside = !inside
    }
    j = i
  }
  return inside
}

/** Check if a point is inside an axis-aligned rectangle. */
function pointInRect(
  lat: number,
  lng: number,
  minLat: number,
  maxLat: number,
  minLng: number,
  maxLng: number,
): boolean {
  return minLat <= lat && lat <= maxLat && minLng <= lng && lng <= maxLng
}

/** Check if segments AB and CD intersect (inclusive). */
function segmentsIntersect(
  aLat: number,
  aLng: number,
  bLat: number,
  bLng: number,
  cLat: number,
  cLng: number,
  dLat: number,
  dLng: number,
): boolean {
  function crossProduct(x1: number, y1: number, x2: number, y2: number): number {
    return x1 * y2 - y1 * x2
  }

  function direction(
    ax: number,
    ay: number,
    bx: number,
    by: number,
    cx: number,
    cy: number,
  ): number {
    return crossProduct(cx - ax, cy - ay, bx - ax, by - ay)
  }

  const d1 = direction(aLng, aLat, bLng, bLat, cLng, cLat)
  const d2 = direction(aLng, aLat, bLng, bLat, dLng, dLat)
  const d3 = direction(cLng, cLat, dLng, dLat, aLng, aLat)
  const d4 = direction(cLng, cLat, dLng, dLat, bLng, bLat)

  if (((d1 > 0 && d2 < 0) || (d1 < 0 && d2 > 0)) && ((d3 > 0 && d4 < 0) || (d3 < 0 && d4 > 0))) {
    return true
  }

  function onSegment(
    px: number,
    py: number,
    qx: number,
    qy: number,
    rx: number,
    ry: number,
  ): boolean {
    return (
      Math.min(px, rx) <= qx &&
      qx <= Math.max(px, rx) &&
      Math.min(py, ry) <= qy &&
      qy <= Math.max(py, ry)
    )
  }

  if (d1 === 0 && onSegment(aLng, aLat, cLng, cLat, bLng, bLat)) return true
  if (d2 === 0 && onSegment(aLng, aLat, dLng, dLat, bLng, bLat)) return true
  if (d3 === 0 && onSegment(cLng, cLat, aLng, aLat, dLng, dLat)) return true
  if (d4 === 0 && onSegment(cLng, cLat, bLng, bLat, dLng, dLat)) return true

  return false
}

/** Check if an axis-aligned rectangle intersects or is inside the polygon. */
function rectIntersectsPolygon(
  minLat: number,
  maxLat: number,
  minLng: number,
  maxLng: number,
  polygon: readonly Point[],
): boolean {
  // 1) Any polygon vertex inside rect
  for (const p of polygon) {
    if (pointInRect(p.latitude, p.longitude, minLat, maxLat, minLng, maxLng)) {
      return true
    }
  }

  // 2) Any rect corner inside polygon
  const rectCorners: Array<[number, number]> = [
    [minLat, minLng],
    [minLat, maxLng],
    [maxLat, maxLng],
    [maxLat, minLng],
  ]
  for (const [lat, lng] of rectCorners) {
    if (pointInPolygon(lat, lng, polygon)) {
      return true
    }
  }

  // 3) Any polygon edge intersecting any rect edge
  const rectEdges: Array<[[number, number], [number, number]]> = [
    [
      [minLat, minLng],
      [minLat, maxLng],
    ],
    [
      [minLat, maxLng],
      [maxLat, maxLng],
    ],
    [
      [maxLat, maxLng],
      [maxLat, minLng],
    ],
    [
      [maxLat, minLng],
      [minLat, minLng],
    ],
  ]

  const n = polygon.length
  if (n < 2) return false

  for (let i = 0; i < n; i++) {
    const a = polygon[i]
    const b = polygon[(i + 1) % n]
    for (const [r1, r2] of rectEdges) {
      if (
        segmentsIntersect(
          a.latitude,
          a.longitude,
          b.latitude,
          b.longitude,
          r1[0],
          r1[1],
          r2[0],
          r2[1],
        )
      ) {
        return true
      }
    }
  }

  return false
}

/**
 * Serialize polygon vertices to a canonical string for hashing.
 *
 * Coordinates are quantized to 5 decimal places (~1.1 m at the equator,
 * >100× below the 256 m tile step) so float precision drift doesn't
 * change the fingerprint. Vertex order is preserved as-given — matches
 * Python SDK's `_polygon_fingerprint` so cross-SDK tile IDs are
 * byte-identical for the same input polygon.
 */
export function polygonFingerprint(polygon: readonly Point[]): string {
  if (polygon.length === 0) return ''
  return polygon
    .map((p) => `${p.latitude.toFixed(5)},${p.longitude.toFixed(5)}`)
    .join(';')
}

// ---------------------------------------------------------------------------
// Tile generation
// ---------------------------------------------------------------------------

/**
 * Generate a 2-D grid of tiles over a polygon bounding box.
 *
 * @param polygon - Polygon vertices (unique, no closing duplicate).
 * @param tileSize - Physical tile dimensions in meters.
 * @param stepM - Step between tile centers in meters (default 256 m for 50% overlap).
 * @returns tiles[row][col] from SW corner, east then north.
 */
function generateTiles(
  polygon: readonly Point[],
  tileSize: TileSize,
  stepM: number = WIND_TILING_CONFIG.stepM,
): Tile[][] {
  const lats = polygon.map((p) => p.latitude)
  const lngs = polygon.map((p) => p.longitude)

  // Stack-safe: spread (`Math.min(...arr)`) crashes on hi-res polygon rings
  // (>~64-128k vertices, engine-dependent).
  const minLat = arrayMin(lats)
  const maxLat = arrayMax(lats)
  const minLng = arrayMin(lngs)
  const maxLng = arrayMax(lngs)

  const metersX = tileSize.x
  const metersY = tileSize.y

  if (metersX <= 0 || metersY <= 0) {
    throw new Error('tileSize.x and tileSize.y must be positive')
  }

  // Approximate meters per degree at the polygon's center latitude
  const centerLatForScale = (minLat + maxLat) / 2.0
  const metersPerDegLng = METERS_PER_DEG_LAT * Math.cos((centerLatForScale * Math.PI) / 180)

  // Step sizes in degrees
  const stepY = stepM / METERS_PER_DEG_LAT
  const stepX = metersPerDegLng !== 0 ? stepM / metersPerDegLng : stepM / METERS_PER_DEG_LAT

  // Half-tile extents in degrees (for bbox intersection checks)
  const halfTileY = metersY / 2.0 / METERS_PER_DEG_LAT
  const halfTileX =
    metersPerDegLng !== 0 ? metersX / 2.0 / metersPerDegLng : metersX / 2.0 / METERS_PER_DEG_LAT

  const numRows = Math.max(1, Math.ceil((maxLat - minLat) / stepY))
  const numCols = Math.max(1, Math.ceil((maxLng - minLng) / stepX))

  const fingerprint = polygonFingerprint(polygon)
  const tiles: Tile[][] = []

  for (let row = 0; row < numRows; row++) {
    const rowTiles: Tile[] = []
    const centerLat = minLat + (row + 0.5) * stepY

    for (let col = 0; col < numCols; col++) {
      const centerLng = minLng + (col + 0.5) * stepX

      const centroid: Point = { latitude: centerLat, longitude: centerLng }

      // Primary check: centroid inside polygon
      const isInside = pointInPolygon(centerLat, centerLng, polygon)

      // If centroid is outside, check if tile bbox intersects polygon
      let intersects: boolean
      if (!isInside) {
        intersects = rectIntersectsPolygon(
          centerLat - halfTileY,
          centerLat + halfTileY,
          centerLng - halfTileX,
          centerLng + halfTileX,
          polygon,
        )
      } else {
        intersects = true
      }

      const tileId = uuidv5(`${fingerprint}:${row}:${col}`, TILE_NAMESPACE)

      rowTiles.push({
        tileId,
        empty: !intersects,
        centroid,
        size: tileSize,
      })
    }

    tiles.push(rowTiles)
  }

  return tiles
}
