/**
 * Grid merger with centre-crop concatenation and polygon clipping.
 *
 * Mirrors the Python SDK's `tiling/merger.py`:
 *   - Each tile's inference grid is cropped to its centre `stepCells × stepCells`
 *     region and placed at `(row * stepCells, col * stepCells)` in the merged grid.
 *   - No overlap, no blending. Wind: 256×256 inner crop from each 512×512 tile.
 *     Solar/UTCI/etc.: full 512×512 placed edge-to-edge (stepCells == inferenceSizeCells).
 *
 * Cells outside the original polygon are set to NaN via cell-level polygon clipping.
 *
 * Uses Float64Array (no NumPy) for isomorphic compatibility.
 */

import { arrayMax, arrayMin } from '../utils'
import {
  cropStartCells,
  type TilingConfig,
  WIND_TILING_CONFIG,
} from './config'
import { mergeDirectional, mergeTilesSmart } from './mergerSmart'
import { METERS_PER_DEG_LAT } from './types'

/**
 * Tile merge strategy. Mirrors Python `tiling/merger.py`:
 *  - `default`            — plain centre-crop placement (no overlap blending).
 *  - `directional`        — argmax-only winner per cell, weighted by an
 *                           upstream-extent reliability mask. Wind-speed only.
 *  - `directional_blend`  — S12a smart-blend (argmax + spread-gated
 *                           upstream-biased Gaussian softening). Wind-speed only.
 */
export type MergeStrategy = 'default' | 'directional' | 'directional_blend'

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Compute the merged grid dimensions for an R × C tile layout.
 *
 * @param numRows - Number of tile rows.
 * @param numCols - Number of tile columns.
 * @param config - Tiling config; defaults to wind config for backwards compat.
 * @returns [height, width] in cells.
 */
export function mergedGridShape(
  numRows: number,
  numCols: number,
  config: TilingConfig = WIND_TILING_CONFIG,
): [number, number] {
  if (numRows < 1 || numCols < 1) {
    throw new Error(`numRows and numCols must be >= 1, got (${numRows}, ${numCols})`)
  }
  return [numRows * config.stepCells, numCols * config.stepCells]
}

/**
 * Map a tile grid position to its start offset in the merged grid.
 *
 * @param row - Tile row index (0-based, south to north).
 * @param col - Tile column index (0-based, west to east).
 * @param config - Tiling config; defaults to wind config for backwards compat.
 * @returns [startRow, startCol] in the merged grid.
 */
export function tileToGridOffset(
  row: number,
  col: number,
  config: TilingConfig = WIND_TILING_CONFIG,
): [number, number] {
  return [row * config.stepCells, col * config.stepCells]
}

/** A tile grid with its position in the overall grid. */
export interface TileGridEntry {
  row: number
  col: number
  /** A flat Float64Array of shape (inferenceSizeCells × inferenceSizeCells). */
  grid: Float64Array
}

/**
 * Merge tile grids into a single array using centre-crop placement.
 *
 * Each tile's inference grid is cropped to its centre `stepCells × stepCells`
 * region and placed at `(row * stepCells, col * stepCells)` in the merged grid.
 *
 * @param tileGrids - Each element is `{row, col, grid}` where grid is a flat
 *   Float64Array of shape (inferenceSizeCells × inferenceSizeCells).
 * @param numRows - Total rows in the tile grid.
 * @param numCols - Total columns in the tile grid.
 * @param config - Tiling config; defaults to wind config for backwards compat.
 * @returns Merged Float64Array, stored row-major. Cells with no contributing
 *   data are NaN.
 */
export function mergeTiles(
  tileGrids: readonly TileGridEntry[],
  numRows: number,
  numCols: number,
  config?: TilingConfig,
  opts?: { strategy?: MergeStrategy; windDirectionDeg?: number },
): { grid: Float64Array; height: number; width: number } {
  const strategy: MergeStrategy = opts?.strategy ?? 'default'
  const windDirectionDeg = opts?.windDirectionDeg

  // Mirrors Python `merger.py:143-178`: directional strategies require
  // both an explicit config and a wind direction; unknown strategies raise.
  if (strategy === 'directional' || strategy === 'directional_blend') {
    if (windDirectionDeg === undefined || windDirectionDeg === null) {
      throw new Error(`strategy=${JSON.stringify(strategy)} requires windDirectionDeg`)
    }
    if (config === undefined || config === null) {
      throw new Error(
        `strategy=${JSON.stringify(strategy)} requires an explicit config; ` +
          `pass WIND_TILING_CONFIG for wind-speed analyses.`,
      )
    }
    if (strategy === 'directional') {
      const ts = config.inferenceSizeCells
      const step = config.stepCells
      const full = mergeDirectional(tileGrids, numRows, numCols, config, {
        windDirectionDeg,
        recoveryLengthCells: 96.0,
        handoffOffset: 0.30,
        radialInscribedRadius: 240.0,
        radialFalloffCells: 24.0,
      })
      const offset = Math.floor((ts - step) / 2)
      const finalH = numRows * step
      const finalW = numCols * step
      const out = new Float64Array(finalH * finalW)
      for (let r = 0; r < finalH; r++) {
        const src = (offset + r) * full.width + offset
        const dst = r * finalW
        for (let c = 0; c < finalW; c++) out[dst + c] = full.grid[src + c]
      }
      return { grid: out, height: finalH, width: finalW }
    }
    return mergeTilesSmart(tileGrids, numRows, numCols, config, { windDirectionDeg })
  }

  if (strategy !== 'default') {
    throw new Error(
      `Unknown merge strategy ${JSON.stringify(strategy)}. ` +
        `Valid values: 'default', 'directional', 'directional_blend'.`,
    )
  }

  const cfg = config ?? WIND_TILING_CONFIG
  const [height, width] = mergedGridShape(numRows, numCols, cfg)
  const merged = new Float64Array(height * width)
  merged.fill(NaN)

  const cropStart = cropStartCells(cfg)
  const step = cfg.stepCells
  const inferenceSize = cfg.inferenceSizeCells
  const expectedSize = inferenceSize * inferenceSize

  for (const entry of tileGrids) {
    const { row, col, grid } = entry

    if (grid.length !== expectedSize) {
      throw new Error(
        `Tile (${row}, ${col}) grid length ${grid.length} != ${expectedSize} ` +
          `(expected ${inferenceSize}×${inferenceSize})`,
      )
    }

    const rStart = row * step
    const cStart = col * step

    // Copy centre crop into merged grid; NaN cells in the source are skipped
    // so they don't overwrite valid data already placed by an earlier tile
    // (no-op for centre-crop — tiles never overlap — but defensive against
    // future changes).
    for (let r = 0; r < step; r++) {
      const tileRow = cropStart + r
      const mergedRow = rStart + r
      for (let c = 0; c < step; c++) {
        const tileCol = cropStart + c
        const value = grid[tileRow * inferenceSize + tileCol]
        if (!Number.isNaN(value)) {
          merged[mergedRow * width + (cStart + c)] = value
        }
      }
    }
  }

  return { grid: merged, height, width }
}

/**
 * Set cells outside the polygon to NaN.
 *
 * Cell centers are tested at
 *   (gridOrigin[0] + (col + 0.5) * cellSizeM,
 *    gridOrigin[1] + (row + 0.5) * cellSizeM)
 * in the tangent-plane meter space.
 *
 * @param grid - Flat Float64Array (modified in place and returned).
 * @param height - Grid height in rows.
 * @param width - Grid width in columns.
 * @param polygonMeters - Polygon vertices in meter-space as [x, y] pairs (open ring).
 * @param gridOrigin - Position of cell (0,0) as [originX, originY]. Default [0, 0].
 * @param cellSizeM - Metres per grid cell (default 1.0).
 * @returns The clipped grid (same array as input).
 */
export function clipToPolygon(
  grid: Float64Array,
  height: number,
  width: number,
  polygonMeters: ReadonlyArray<readonly [number, number]>,
  gridOrigin: readonly [number, number] = [0.0, 0.0],
  cellSizeM = 1.0,
): Float64Array {
  const [originX, originY] = gridOrigin
  const n = polygonMeters.length

  // Fewer than 3 vertices is not a polygon: every cell is "outside". Matches
  // the scalar ray-cast (`n < 3 -> false` for every point).
  if (n < 3) {
    grid.fill(NaN)
    return grid
  }

  // Flatten the ring into typed arrays once. The scalar path re-read
  // `polygon[i][0]` (a nested-array pointer chase) for every cell × every
  // edge; doing it once here removes that from the hot loop, and lets us
  // compute the polygon y-extent for row-level rejection.
  const xs = new Float64Array(n)
  const ys = new Float64Array(n)
  let minY = Infinity
  let maxY = -Infinity
  for (let k = 0; k < n; k++) {
    xs[k] = polygonMeters[k][0]
    const y = polygonMeters[k][1]
    ys[k] = y
    if (y < minY) minY = y
    if (y > maxY) maxY = y
  }

  // Scratch buffer for the x-intersections of the edges that straddle the
  // current scanline row. At most `n` edges can straddle (usually 2).
  const crossings = new Float64Array(n)

  // Scanline even-odd ray cast. This is the SAME algorithm as the per-cell
  // `pointInPolygonXY`, reorganised so the per-edge intersection is computed
  // once per row instead of once per cell:
  //   * A horizontal scanline outside [minY, maxY] crosses no edge, so the
  //     whole row is outside (crossing count 0 for every cell).
  //   * Otherwise compute, for each straddling edge, the x where it crosses
  //     the row — the IDENTICAL expression (same operand order, same 1e-12
  //     epsilon) as the scalar code. A cell at `cx` is inside iff an odd
  //     number of those crossings lie strictly to its right (`cx < xint`).
  // Even-odd parity is a crossing *count* parity, so it is order-independent:
  // reordering the per-edge evaluation cannot change the classification. The
  // result is therefore byte-for-byte identical to the scalar ray-cast,
  // including on-vertex / on-edge cells. Locked by tests/tiling/merger-golden.
  for (let r = 0; r < height; r++) {
    const cy = originY + (r + 0.5) * cellSizeM
    const rowBase = r * width

    if (cy < minY || cy > maxY) {
      for (let c = 0; c < width; c++) grid[rowBase + c] = NaN
      continue
    }

    let m = 0
    let j = n - 1
    for (let i = 0; i < n; i++) {
      const yi = ys[i]
      const yj = ys[j]
      if (yi > cy !== yj > cy) {
        crossings[m++] = ((xs[j] - xs[i]) * (cy - yi)) / (yj - yi + 1e-12) + xs[i]
      }
      j = i
    }

    if (m === 0) {
      for (let c = 0; c < width; c++) grid[rowBase + c] = NaN
      continue
    }

    for (let c = 0; c < width; c++) {
      const cx = originX + (c + 0.5) * cellSizeM
      let count = 0
      for (let k = 0; k < m; k++) {
        if (cx < crossings[k]) count++
      }
      if ((count & 1) === 0) grid[rowBase + c] = NaN
    }
  }

  return grid
}

/**
 * Project a GeoJSON polygon to tangent-plane meter space.
 *
 * Origin is the bounding box SW corner. Uses the same local tangent
 * plane approximation as the tile generation module.
 */
export function projectPolygonToMeters(geojsonPolygon: {
  coordinates: ReadonlyArray<ReadonlyArray<readonly [number, number, ...number[]]>>
}): {
  polygonMeters: Array<[number, number]>
  originLon: number
  originLat: number
} {
  const ring = geojsonPolygon.coordinates[0]
  let vertices: ReadonlyArray<readonly [number, number, ...number[]]>
  if (
    ring.length > 1 &&
    ring[0][0] === ring[ring.length - 1][0] &&
    ring[0][1] === ring[ring.length - 1][1]
  ) {
    vertices = ring.slice(0, -1)
  } else {
    vertices = ring
  }

  const lons = vertices.map((v) => v[0])
  const lats = vertices.map((v) => v[1])

  const originLon = arrayMin(lons)
  const originLat = arrayMin(lats)

  const centerLat = (arrayMin(lats) + arrayMax(lats)) / 2.0
  const metersPerDegLng = METERS_PER_DEG_LAT * Math.cos((centerLat * Math.PI) / 180)

  const polygonMeters: Array<[number, number]> = vertices.map((v) => [
    (v[0] - originLon) * metersPerDegLng,
    (v[1] - originLat) * METERS_PER_DEG_LAT,
  ])

  return { polygonMeters, originLon, originLat }
}

/**
 * Convert a Float64Array grid to a nested array with NaN replaced by null.
 * Suitable for JSON serialization.
 */
export function gridToList(
  grid: Float64Array,
  height: number,
  width: number,
): Array<Array<number | null>> {
  const result: Array<Array<number | null>> = new Array(height)
  for (let r = 0; r < height; r++) {
    const base = r * width
    const row: Array<number | null> = new Array(width)
    for (let c = 0; c < width; c++) {
      const val = grid[base + c]
      // `val === val` is false only for NaN — same result as Number.isNaN(val),
      // and the surviving value is passed through unchanged (NaN -> null).
      row[c] = val === val ? val : null
    }
    result[r] = row
  }
  return result
}

